async def run(args, state):
    query = args.get('query')
    if not query:
        return 'Пожалуйста, укажите поисковый запрос.'
    raw = await rag_search(
        namespace_id='psychology',
        collection_id='default',
        query=query,
        limit=3,
    )
    if not raw.get('success'):
        return str(raw.get('error', 'Ошибка поиска'))
    results = raw.get('results') or []
    if not results:
        return 'В психологической базе знаний ничего не найдено по данному запросу.'
    output = []
    for res in results:
        name = res.get('document_name') or res.get('document_id', '')
        output.append(f"--- {name} ---\n{res.get('content', '')}")
    return '\n\n'.join(output)
